'use client'
import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { getSession } from '@/lib/crm'

type Tab = 'bestaetigung' | 'zugangsdaten' | 'info'
declare global { interface Window { google: any } }

const CLIENT_ID = process.env.NEXT_PUBLIC_GMAIL_CLIENT_ID || ''
const SCOPES = 'https://www.googleapis.com/auth/gmail.send'
const LOGO_URI = 'data:image/png;base64,'

function b64(str: string) {
  return btoa(unescape(encodeURIComponent(str))).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '')
}

async function sendGmail(token: string, to: string, subject: string, html: string, pdfB64?: string, pdfName?: string) {
  let lines: string[]
  if (pdfB64 && pdfName) {
    const bnd = 'mz_' + Date.now()
    lines = [`To: ${to}`,`Subject: =?UTF-8?B?${btoa(unescape(encodeURIComponent(subject)))}?=`,'MIME-Version: 1.0',`Content-Type: multipart/mixed; boundary="${bnd}"`,'',`--${bnd}`,'Content-Type: text/html; charset=UTF-8','Content-Transfer-Encoding: base64','',b64(html),'',`--${bnd}`,`Content-Type: application/pdf; name="${pdfName}"`,'Content-Transfer-Encoding: base64',`Content-Disposition: attachment; filename="${pdfName}"`,'',pdfB64,`--${bnd}--`]
  } else {
    lines = [`To: ${to}`,`Subject: =?UTF-8?B?${btoa(unescape(encodeURIComponent(subject)))}?=`,'MIME-Version: 1.0','Content-Type: text/html; charset=UTF-8','Content-Transfer-Encoding: base64','',b64(html)]
  }
  const res = await fetch('https://gmail.googleapis.com/gmail/v1/users/me/messages/send', {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ raw: b64(lines.join('\r\n')) }),
  })
  if (!res.ok) throw new Error(await res.text())
}

const HDR = `<div style="background:#000;padding:16px 24px;"><img src="${LOGO_URI}" alt="Meizo" style="height:52px;width:52px;border-radius:12px;display:block;"></div>`
const FTR = `<div style="background:#f7f7f7;padding:14px 28px;display:flex;justify-content:space-between;font-size:11px;color:#aaa;border-top:1px solid #eee;"><span>&copy; 2026 Meizo</span><span>M&uuml;nchen, Deutschland</span></div>`
function SIG(name: string) { return `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #eee;"><p style="font-weight:600;font-size:14px;margin:0;">${name}</p><p style="font-size:12px;color:#999;margin:2px 0 0;">Meizo &middot; meizo.de</p></div>` }

const NOTIZ = `Bitte halten Sie f&uuml;r unser Gespr&auml;ch folgende Informationen bereit:<br><br>&ndash; Die Namen Ihrer 3 wichtigsten Objekte (z.B. B&uuml;rogeb&auml;ude, Wohnanlage)<br>&ndash; Die Namen von 3 Ihrer Mitarbeiter inkl. Handynummer<br><br>Das erm&ouml;glicht mir, Ihnen Meizo direkt im Gespr&auml;ch live einzurichten &ndash; Sie sehen sofort, wie es f&uuml;r Ihr Unternehmen aussieht.`
const ANREDEN = ['Sehr geehrter Herr', 'Sehr geehrte Frau', 'Sehr geehrte Damen und Herren']

export default function EmailPage() {
  const router = useRouter()
  const [tab, setTab] = useState<Tab>('bestaetigung')
  const [authed, setAuthed] = useState(false)
  const [gmail, setGmail] = useState(false)
  const tokenRef = useRef<any>(null)
  const tokenVal = useRef('')
  const [status, setStatus] = useState('')
  const [statusErr, setStatusErr] = useState(false)

  const [gAnrede, setGA] = useState('Sehr geehrter Herr')
  const [gName, setGN] = useState('')
  const [gDatum, setGD] = useState('')
  const [gUhrzeit, setGU] = useState('')
  const [gZoom, setGZ] = useState('')
  const [gSender, setGS] = useState('')
  const [gTo, setGTo] = useState('')

  const [zAnrede, setZA] = useState('Sehr geehrter Herr')
  const [zName, setZN] = useState('')
  const [zEmail, setZE] = useState('')
  const [zPw, setZP] = useState('')
  const [zSender, setZS] = useState('')
  const [zTo, setZTo] = useState('')

  const [iAnrede, setIA] = useState('Sehr geehrter Herr')
  const [iName, setIN] = useState('')
  const [iSender, setIS] = useState('')
  const [iTo, setITo] = useState('')
  const [iPdf, setIPdf] = useState<File | null>(null)
  const [iPdfB64, setIPdfB64] = useState('')
  const pdfRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    const s = getSession(); if (!s) { router.replace('/'); return }
    setAuthed(true)
    if (!CLIENT_ID) {
      setStatus('Gmail OAuth nicht konfiguriert (NEXT_PUBLIC_GMAIL_CLIENT_ID fehlt)')
      setStatusErr(true)
      return
    }
    const sc = document.createElement('script')
    sc.src = 'https://accounts.google.com/gsi/client'
    sc.onload = () => {
      tokenRef.current = window.google.accounts.oauth2.initTokenClient({
        client_id: CLIENT_ID, scope: SCOPES,
        callback: (r: any) => { if (r.access_token) { tokenVal.current = r.access_token; setGmail(true) } }
      })
    }
    document.head.appendChild(sc)
  }, [router])

  function handlePdf(e: React.ChangeEvent<HTMLInputElement>) {
    const f = e.target.files?.[0]; if (!f) return; setIPdf(f)
    const rd = new FileReader(); rd.onload = ev => setIPdfB64((ev.target?.result as string).split(',')[1]); rd.readAsDataURL(f)
  }

  async function doSend(html: string, to: string, subject: string, pdfB64?: string, pdfName?: string) {
    if (!gmail) { show('Bitte zuerst Gmail verbinden', true); return }
    if (!to) { show('Empfänger-E-Mail fehlt', true); return }
    try { await sendGmail(tokenVal.current, to, subject, html, pdfB64, pdfName); show('✓ E-Mail gesendet', false) }
    catch (e: any) { show('Fehler: ' + e.message, true) }
  }

  function show(msg: string, err: boolean) { setStatus(msg); setStatusErr(err); setTimeout(() => setStatus(''), 3500) }

  function gHtml() { return `<div style="font-family:-apple-system,sans-serif;max-width:600px;">${HDR}<div style="background:#fff;padding:32px 28px;font-size:14px;line-height:1.75;color:#222;"><p style="font-size:11px;color:#aaa;letter-spacing:.5px;text-transform:uppercase;margin:0 0 20px;">Gespr&auml;chsbest&auml;tigung</p><p style="margin:0 0 10px;">${gAnrede} <strong>${gName||'...'}</strong>,</p><p style="margin:0 0 10px;">wir freuen uns, Ihnen zu best&auml;tigen, dass unser Gespr&auml;ch am <strong>${gDatum||'...'}</strong> um <strong>${gUhrzeit||'...'}</strong> stattfinden wird.</p><p style="margin:0 0 10px;">Hier ist Ihr Link zum Meeting:</p><a href="${gZoom}" style="display:inline-block;margin:8px 0 18px;background:#111;color:#fff;padding:11px 22px;border-radius:7px;text-decoration:none;font-size:13px;font-weight:600;">Zoom-Meeting beitreten</a><div style="margin:16px 0;padding:16px 20px;background:#f9f9f9;border-radius:8px;border-left:3px solid #111;font-size:13px;color:#444;line-height:1.8;">${NOTIZ}</div><p style="margin:10px 0 0;">Falls Sie Fragen haben, stehen wir Ihnen gerne zur Verf&uuml;gung.</p>${SIG(gSender||'...')}</div>${FTR}</div>` }
  function zHtml() { return `<div style="font-family:-apple-system,sans-serif;max-width:600px;">${HDR}<div style="background:#fff;padding:32px 28px;font-size:14px;line-height:1.75;color:#222;"><p style="font-size:11px;color:#aaa;letter-spacing:.5px;text-transform:uppercase;margin:0 0 20px;">Ihre Zugangsdaten</p><p style="margin:0 0 10px;">${zAnrede} <strong>${zName||'...'}</strong>,</p><p style="margin:0 0 10px;">vielen Dank f&uuml;r Ihr Vertrauen. Hier sind Ihre pers&ouml;nlichen Zugangsdaten f&uuml;r <strong>meizo.de</strong>:</p><div style="margin:20px 0;background:#f7f7f7;border-radius:8px;border:1px solid #eee;overflow:hidden;"><div style="padding:12px 22px;border-bottom:1px solid #eee;display:flex;justify-content:space-between;"><span style="font-size:12px;color:#888;">E-Mail</span><span style="font-size:14px;font-weight:600;color:#111;">${zEmail||'...'}</span></div><div style="padding:12px 22px;display:flex;justify-content:space-between;"><span style="font-size:12px;color:#888;">Passwort</span><span style="font-size:14px;font-weight:600;color:#111;">${zPw||'...'}</span></div></div><a href="https://meizo.de" style="display:inline-block;margin:8px 0 18px;background:#111;color:#fff;padding:11px 22px;border-radius:7px;text-decoration:none;font-size:13px;font-weight:600;">Jetzt einloggen &rarr;</a><p style="color:#555;font-size:13px;margin:0 0 8px;">Sie k&ouml;nnen Ihr Passwort nach dem ersten Login jederzeit &auml;ndern.</p><p style="margin:10px 0 0;color:#555;font-size:13px;">Bei Fragen stehen wir Ihnen gerne zur Verf&uuml;gung.</p>${SIG(zSender||'...')}</div>${FTR}</div>` }
  function iHtml() { return `<div style="font-family:-apple-system,sans-serif;max-width:600px;">${HDR}<div style="background:#fff;padding:32px 28px;font-size:14px;line-height:1.75;color:#222;"><p style="font-size:11px;color:#aaa;letter-spacing:.5px;text-transform:uppercase;margin:0 0 20px;">Infomaterial</p><p style="margin:0 0 10px;">${iAnrede} <strong>${iName||'...'}</strong>,</p><p style="margin:0 0 10px;">vielen Dank f&uuml;r das angenehme Telefonat.</p><p style="margin:0 0 10px;">Wie versprochen, finden Sie im Anhang unsere Informationsbr&ouml;sch&uuml;re. Einen ersten visuellen Eindruck unserer Software erhalten Sie zudem direkt auf unserer Website: <a href="https://meizo.de" style="color:#111;font-weight:600;">meizo.de</a></p><p style="margin:0 0 10px;">Da gedruckte Infos aber nie ein Live-Erlebnis ersetzen: Lassen Sie uns kurz f&uuml;r 10&ndash;15 Minuten in einem Zoom-Meeting zusammenkommen. Ich zeige Ihnen die Software direkt von innen, damit Sie sofort sehen, welchen konkreten Mehrwert sie f&uuml;r Ihren Alltag bietet.</p><p style="margin:0 0 10px;">Als Bonus richten wir Ihnen im Anschluss gerne einen kostenlosen, einmonatigen Testzugang ein &ndash; v&ouml;llig unverbindlich.</p><p style="margin:0 0 20px;">Passt es Ihnen n&auml;chste Woche <strong>Dienstag um 10:00 Uhr</strong> oder <strong>Donnerstag um 14:00 Uhr</strong> f&uuml;r einen kurzen Blick &uuml;ber die Software?</p><p style="margin:0 0 4px;">Mit freundlichen Gr&uuml;&szlig;en</p>${SIG(iSender||'...')}</div>${FTR}</div>` }

  if (!authed) return null

  const TABS = [{id:'bestaetigung' as Tab,label:'📅 Gesprächsbestätigung'},{id:'zugangsdaten' as Tab,label:'🔑 Zugangsdaten'},{id:'info' as Tab,label:'📄 Info-Mail'}]

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)', paddingBottom: 60 }}>
      <div style={{ maxWidth: 1200, margin: '0 auto', padding: '24px 20px' }}>
        <div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 12, padding: '14px 20px', marginBottom: 24, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <span style={{ fontSize: 14, color: gmail ? '#16a34a' : 'var(--text-muted)' }}>{gmail ? '✓ Gmail verbunden' : 'Nicht verbunden – bitte Gmail verbinden'}</span>
          {!gmail ? <button onClick={() => tokenRef.current?.requestAccessToken()} style={bD}>Mit Gmail verbinden</button> : <button onClick={() => { tokenVal.current=''; setGmail(false) }} style={bO}>Abmelden</button>}
        </div>
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          {TABS.map(t => <button key={t.id} onClick={() => setTab(t.id)} style={{ padding: '9px 20px', borderRadius: 8, fontSize: 14, fontWeight: 500, cursor: 'pointer', background: tab===t.id?'var(--text)':'var(--surface)', color: tab===t.id?'var(--bg)':'var(--text-secondary)', border: tab===t.id?'none':'1px solid var(--border)' }}>{t.label}</button>)}
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 24 }}>
          <div style={pnl}>
            <div style={slbl}>Felder ausfüllen</div>
            {tab==='bestaetigung' && <><F l="Anrede"><select value={gAnrede} onChange={e=>setGA(e.target.value)} style={inp}>{ANREDEN.map(a=><option key={a}>{a}</option>)}</select></F><F l="Nachname"><input value={gName} onChange={e=>setGN(e.target.value)} placeholder="Mustermann" style={inp}/></F><F l="Datum"><input value={gDatum} onChange={e=>setGD(e.target.value)} placeholder="20. Juni 2026" style={inp}/></F><F l="Uhrzeit"><input value={gUhrzeit} onChange={e=>setGU(e.target.value)} placeholder="14:00 Uhr" style={inp}/></F><F l="Zoom-Link"><input value={gZoom} onChange={e=>setGZ(e.target.value)} placeholder="https://zoom.us/j/..." style={inp}/></F><F l="Absender Name"><input value={gSender} onChange={e=>setGS(e.target.value)} placeholder="Giorgi Beridze" style={inp}/></F><F l="An (E-Mail des Kunden)"><input type="email" value={gTo} onChange={e=>setGTo(e.target.value)} placeholder="kunde@firma.de" style={inp}/></F><button onClick={()=>doSend(gHtml(),gTo,'Gesprächsbestätigung – Meizo')} style={{...bD,width:'100%',marginTop:20}}>✉ Via Gmail senden</button></>}
            {tab==='zugangsdaten' && <><F l="Anrede"><select value={zAnrede} onChange={e=>setZA(e.target.value)} style={inp}>{ANREDEN.map(a=><option key={a}>{a}</option>)}</select></F><F l="Nachname"><input value={zName} onChange={e=>setZN(e.target.value)} placeholder="Mustermann" style={inp}/></F><F l="Login E-Mail des Kunden"><input type="email" value={zEmail} onChange={e=>setZE(e.target.value)} placeholder="mustermann@firma.de" style={inp}/></F><F l="Passwort"><input value={zPw} onChange={e=>setZP(e.target.value)} placeholder="Meizo2026!" style={inp}/></F><F l="Absender Name"><input value={zSender} onChange={e=>setZS(e.target.value)} placeholder="Giorgi Beridze" style={inp}/></F><F l="An (E-Mail des Kunden)"><input type="email" value={zTo} onChange={e=>setZTo(e.target.value)} placeholder="kunde@firma.de" style={inp}/></F><button onClick={()=>doSend(zHtml(),zTo,'Ihre Zugangsdaten – Meizo')} style={{...bD,width:'100%',marginTop:20}}>✉ Via Gmail senden</button></>}
            {tab==='info' && <><F l="Anrede"><select value={iAnrede} onChange={e=>setIA(e.target.value)} style={inp}>{ANREDEN.map(a=><option key={a}>{a}</option>)}</select></F><F l="Nachname"><input value={iName} onChange={e=>setIN(e.target.value)} placeholder="Mustermann" style={inp}/></F><F l="Ihr Name (nach 'Mit freundlichen Grüßen')"><input value={iSender} onChange={e=>setIS(e.target.value)} placeholder="z.B. Giorgi Beridze" style={inp}/></F><F l="An (E-Mail des Kunden)"><input type="email" value={iTo} onChange={e=>setITo(e.target.value)} placeholder="kunde@firma.de" style={inp}/></F><F l="PDF-Anhang (optional)"><input ref={pdfRef} type="file" accept="application/pdf" onChange={handlePdf} style={{display:'none'}}/><button onClick={()=>pdfRef.current?.click()} style={{...bO,width:'100%',padding:'9px 12px',textAlign:'left' as const}}>{iPdf?`📎 ${iPdf.name}`:'+ PDF auswählen'}</button></F><button onClick={()=>doSend(iHtml(),iTo,'Wie besprochen: Infos zu Meizo / Ihr Testzugang',iPdfB64||undefined,iPdf?.name)} style={{...bD,width:'100%',marginTop:20}}>✉ Via Gmail senden</button></>}
            {status && <div style={{marginTop:12,fontSize:13,textAlign:'center',color:statusErr?'#dc2626':'#16a34a'}}>{status}</div>}
          </div>
          <div style={pnl}>
            <div style={slbl}>Vorschau</div>
            <div style={{border:'1px solid var(--border)',borderRadius:10,overflow:'hidden',fontSize:13}} dangerouslySetInnerHTML={{__html:tab==='bestaetigung'?gHtml():tab==='zugangsdaten'?zHtml():iHtml()}}/>
          </div>
        </div>
      </div>
    </div>
  )
}

function F({l,children}:{l:string;children:React.ReactNode}) {
  return <div style={{marginBottom:12}}><label style={{display:'block',fontSize:12,fontWeight:500,color:'var(--text-muted)',marginBottom:5,textTransform:'uppercase' as const,letterSpacing:'0.04em'}}>{l}</label>{children}</div>
}

const pnl:React.CSSProperties={background:'var(--surface)',border:'1px solid var(--border)',borderRadius:14,padding:24}
const slbl:React.CSSProperties={fontSize:11,fontWeight:600,color:'var(--text-muted)',textTransform:'uppercase',letterSpacing:'0.05em',marginBottom:18}
const inp:React.CSSProperties={width:'100%',padding:'9px 12px',fontSize:14,border:'1px solid var(--border)',borderRadius:8,background:'var(--bg)',color:'var(--text)',outline:'none'}
const bD:React.CSSProperties={padding:'9px 18px',background:'var(--text)',color:'var(--bg)',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}
const bO:React.CSSProperties={padding:'6px 14px',background:'none',border:'1px solid var(--border)',borderRadius:6,fontSize:13,cursor:'pointer',color:'var(--text-secondary)'}
